import { mkdir, writeFile } from 'node:fs/promises'
import { supportedArgs } from 'curlconverter/dist/src/generators/json.js'

const args = [...supportedArgs].sort((left, right) => left.localeCompare(right))
const source = `// Generated by scripts/generate-curl-metadata.mjs from curlconverter.
// Do not edit by hand.

export const CURL_SUPPORTED_ARGS = ${JSON.stringify(args, null, 2)} as const
`

await mkdir('src/generated', { recursive: true })
await writeFile('src/generated/curlMetadata.ts', source)
